def preprocessar_texto(texto):
    if not texto:
        return ""
    texto = texto.lower()
    texto = re.sub(r'[^\w\s]', ' ', texto)  # Remove pontuação
    palavras = nltk.word_tokenize(texto)

    # Stopwords em PT e EN
    stop_words = set(stopwords.words('portuguese')).union(set(stopwords.words('english')))
    palavras_limpas = [p for p in palavras if p not in stop_words]

    return " ".join(palavras_limpas)

def classificar_ods(titulo, texto_conteudo):
    texto_completo = f"{titulo} {texto_conteudo}"
    texto_tratado = preprocessar_texto(texto_completo)

    ods_identificados = {}

    for ods, keywords in ods_keywords.items():
        contagem_ods = 0
        for kw in keywords:
            padrao = rf"\b{re.escape(kw.lower())}\b"
            correspondencias = len(re.findall(padrao, texto_tratado))
            contagem_ods += correspondencias

        if contagem_ods > 0:
            ods_identificados[ods] = contagem_ods

    return ods_identificados

def processar_multiplos_ficheiros_e_gravar_chunks(padrao_ficheiros, chunk_size=1000):
    dados_consolidados = {}

    ficheiros_entrada = sorted(glob.glob(padrao_ficheiros))

    if not ficheiros_entrada:
        print(f"Nenhum ficheiro encontrado com o padrão: {padrao_ficheiros}")
        return

    print(f"Ficheiros encontrados para processamento: {ficheiros_entrada}")

    for caminho_ficheiro in ficheiros_entrada:
        print(f"A ler e a analisar: {os.path.basename(caminho_ficheiro)}...")

        with open(caminho_ficheiro, 'r', encoding='utf-8') as f:
            dados_ficheiro = json.load(f)

        for url, info in dados_ficheiro.items():
            titulo = info.get("titulo", "")
            texto_conteudo = info.get("texto", "")

            ods_mapeados = classificar_ods(titulo, texto_conteudo)

            item_resultado = info.copy()
            item_resultado["ods_mapeados"] = ods_mapeados
            dados_consolidados[url] = item_resultado

    itens_lista = list(dados_consolidados.items())
    total_registos = len(itens_lista)
    num_chunks = math.ceil(total_registos / chunk_size)

    print(f"\nProcessamento concluído. Total de registos acumulados: {total_registos}.")
    print(f"A exportar para {num_chunks} ficheiro(s) de saída dentro da pasta 'documents'...")

    for i in range(num_chunks):
        inicio = i * chunk_size
        fim = inicio + chunk_size
        chunk_atual = dict(itens_lista[inicio:fim])

        nome_ficheiro_saida = f"documents/resultados_ods_{i+1}.json"

        with open(nome_ficheiro_saida, 'w', encoding='utf-8') as f_saida:
            json.dump(chunk_atual, f_saida, indent=2, ensure_ascii=False)

        print(f"-> Gravado com sucesso: {nome_ficheiro_saida} ({len(chunk_atual)} itens)")

processar_multiplos_ficheiros_e_gravar_chunks('documents/documents_formatted_*.json', chunk_size=1000)

